var doc = uiapp.ActiveUIDocument.Document;
var view = uiapp.ActiveUIDocument.ActiveView;
if (view.ViewType != ViewType.DrawingSheet) return new { exported = false, reason = "active view is not a sheet; open a sheet first" };
var tempDir = System.IO.Path.Combine(System.IO.Path.GetTempPath(), "aware-revit-pdf");
System.IO.Directory.CreateDirectory(tempDir);
var opts = new PDFExportOptions { FileName = "aware-export", Combine = true };
var viewSet = new List<ElementId> { view.Id };
bool ok = doc.Export(tempDir, viewSet, opts);
return new { exported = ok, path = System.IO.Path.Combine(tempDir, "aware-export.pdf") };
